{
  "competency_groups": [
    {
      "code": "CG-1",
      "title": "Understands numbers and number sets",
      "description": "Develops understanding of numbers, including the set of real numbers and its properties.",
      "competencies": [
        "C-1.1: Develops understanding of numbers, including the set of real numbers and its properties."
      ],
      "unit_name": "Number System",
      "chapter_name": "Number System"
    },
    {
      "code": "CG-2",
      "title": "Builds deductive and inductive logic for proofs",
      "description": "Understands powers (radical powers) and exponents.",
      "competencies": [
        "C-2.1: Understanding of powers (radical powers) and exponents."
      ],
      "unit_name": "Number System",
      "chapter_name": "Number System"
    },
    {
      "code": "CG-3",
      "title": "Discovers algebraic identities and models real-life situations",
      "description": "States and proves remainder theorem, factor theorem, division algorithm; models contextualised problems using equations.",
      "competencies": [
        "C-3.1: States and proves remainder theorem, factor theorem, and division algorithm.",
        "C-3.2: Models and solves contextualised problems using equations (for example, simultaneous linear equations in two variables or single polynomial equations), and draws conclusions about a situation being modelled."
      ],
      "unit_name": "Algebra",
      "chapter_name": "Introduction to Polynomials"
    },
    {
      "code": "CG-4",
      "title": "Analyses characteristics of 2D geometric shapes and develops arguments",
      "description": "Describes relationships including congruence; proves theorems using Euclid's axioms for triangles, quadrilaterals, circles.",
      "competencies": [
        "C-4.1: Describes relationships including congruence of two-dimensional geometric shapes (such as lines, angles, triangles) to make and test conjectures and solve problems.",
        "C-4.2: Proves theorems using Euclid's axioms and postulates for triangles and quadrilaterals, and applies them to solve geometric problems."
      ],
      "unit_name": "Geometry",
      "chapter_name": "Introduction to Euclid's Geometry"
    },
    {
      "code": "CG-5",
      "title": "Derives and uses formulae for areas, surface area, and volumes",
      "description": "Visualises Heron's formula; visualises mathematical thinking to discover formulae for solid objects.",
      "competencies": [
        "C-5.1: Visualises, represents, and calculates the area of a triangle using Heron's formula and its generalisation to cyclic quadrilaterals given by Brahmagupta's formula."
      ],
      "unit_name": "Mensuration",
      "chapter_name": "Area of shapes"
    },
    {
      "code": "CG-6",
      "title": "Analyses and interprets data using statistical concepts and probability",
      "description": "Applies measures of central tendencies; applies concepts from probability to solve problems.",
      "competencies": [
        "C-6.1: Applies measures of central tendencies, such as mean, median, and mode."
      ],
      "unit_name": "Statistics and Probability",
      "chapter_name": "Statistics"
    },
    {
      "code": "CG-7",
      "title": "Perceives the axiomatic structure of Mathematics",
      "description": "Proves mathematical statements; visualises geometric proofs for algebraic identities.",
      "competencies": [
        "C-7.1: Proves mathematical statements and carries out geometric constructions using stated assumptions, axioms, postulates, definitions, and mathematics vocabulary."
      ],
      "unit_name": "Geometry",
      "chapter_name": "Introduction to Euclid's Geometry"
    },
    {
      "code": "CG-8",
      "title": "Builds skills in visualisation, optimisation, representation, and modelling",
      "description": "Models daily-life phenomena; uses 2D representations of 3D objects.",
      "competencies": [
        "C-8.1: Models daily-life phenomena and uses representations, such as graphs, tables, and equations to draw conclusions."
      ],
      "unit_name": "Algebra",
      "chapter_name": "Introduction to Polynomials"
    },
    {
      "code": "CG-9",
      "title": "Develops computational thinking",
      "description": "Decomposes problems; describes sequences of instructions.",
      "competencies": [
        "C-9.1: Decomposes a problem into sub-problems."
      ],
      "unit_name": "Number System",
      "chapter_name": "Number System"
    },
    {
      "code": "CG-10",
      "title": "Knows and appreciates contributions of mathematicians from India and around the world",
      "description": "Recognises important contributions made by mathematicians in the field.",
      "competencies": [
        "C-10.1: Recognises the important contributions made by mathematicians (Indian and others) in the field of Mathematics."
      ],
      "unit_name": "Geometry",
      "chapter_name": "Introduction to Euclid's Geometry"
    },
    {
      "code": "CG-11",
      "title": "Explores connections of Mathematics with other subjects",
      "description": "Applies mathematical knowledge and tools to analyse problems in multiple subjects.",
      "competencies": [
        "C-11.1: Applies mathematical knowledge and tools to analyse problems or situations in multiple subjects across Science, Social Science, Visual Arts, Music, Vocational Education, and Sports."
      ],
      "unit_name": "Algebra",
      "chapter_name": "Sequences and Progressions"
    }
  ]
}
